INSERT INTO `v1_0011c07719c837deb707bea935534f9fcd2fa2910e256da1f68049bfd32582c8` VALUES (0, 10, 105611, 20052, 0, "そうかい。\nじゃあまずは、焚火の枝を集める運命を\n受け入れてもらえるかい？", 1, 11, 1200520010, 1, 0);
