INSERT INTO `v1_0011c07719c837deb707bea935534f9fcd2fa2910e256da1f68049bfd32582c8` VALUES ("", 0, "vo_travel_talk", 20172, "", "vo_travel_talk_20017_02", 0, 21, 1201720014, "", "");
INSERT INTO `v1_0011c07719c837deb707bea935534f9fcd2fa2910e256da1f68049bfd32582c8` VALUES (0, 10, 106511, 20172, 0, "おいおい、つまんないこと言うなよ。\n確かに大変だけど、だからこそ\n面白がってみるのも大事だと思うぜ。", 1, 11, 1201720015, 1, 0);
