INSERT INTO `v1_0011c07719c837deb707bea935534f9fcd2fa2910e256da1f68049bfd32582c8` VALUES (0, 10, 106111, 20192, 0, "よーし！　ネネカと一緒に冒険だ！\nせっかくだし、何か悪いことするか？\n七冠とやれば派手になりそうだしさ！", 1, 11, 1201920005, 1, 0);
