INSERT INTO `v1_0011c07719c837deb707bea935534f9fcd2fa2910e256da1f68049bfd32582c8` VALUES (0, 10, 107011, 20192, 0, "はぁ……謹んでお断りします。\nそれと悪事というのは露見しないよう、\nこっそりと行うものですよ？", 1, 11, 1201920010, 1, 0);
