INSERT INTO `v1_0011c07719c837deb707bea935534f9fcd2fa2910e256da1f68049bfd32582c8` VALUES (0, 10, 104611, 20232, 0, "ミフユはいっつも働きすぎにゃ。\n休憩はのんびりゆっくりするものにゃ。\nここで一緒に日向ぼっこするにゃ～♪", 1, 11, 1202320010, 1, 0);
